final:
module RefModule(
    input clk,
    input reset,
    input enable,
    input [15:0] data_in,
    output reg [15:0] data_out
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            data_out <= 16'b0;
        else if (enable)
            data_out <= data_in;
    end
endmodule
